function report = runRpc00bHeightTest(options)
%RUNRPC00BHEIGHTTEST Normal-label RPC00B real-image smoke test.
%
% The input RPC00B TREs always describe the full-resolution images. A common
% integer DownsampleFactor filters both images while Rpc00bCamera preserves
% the exact full-resolution TRE coordinates. HeightRangeHAEMetres supplies
% [minimum,expected,maximum]; measured RPC ||dw/dz|| generates the executed
% labels while retaining the expected height exactly. Raw ZNCC winner-take-
% all, guarded sublabel refinement, and frozen physical-height SGM remain
% separate.
%
% Example:
%   report = runRpc00bHeightTest( ...
%       ReferenceImage="reference.ntf", MovingImage="moving.ntf", ...
%       ReferenceTre="reference_rpc00b.txt", ...
%       MovingTre="moving_rpc00b.txt", ...
%       HeightRangeHAEMetres=[100,150,225], DownsampleFactor=8);
% Native 1x ROI example (the same values are reused at every factor):
%   report = runRpc00bHeightTest(..., DownsampleFactor=1, ...
%       ReferenceROI=[2001,4000,6001,8000]);
%
% Traceability: algo/main.tex Algorithm 1, Eqs. (1)--(2), (52)--(55),
% (68)--(76), and Secs. 5.1, 5.4, 5.6--5.7; P1 projected-motion label
% policy; data contract Phase B0; long-range workplan milestone R1.

arguments
    options.ReferenceImage (1, 1) string {mustBeExistingFile}
    options.MovingImage (1, 1) string {mustBeExistingFile}
    options.ReferenceTre {mustBeRpcSource}
    options.MovingTre {mustBeRpcSource}
    options.HeightRangeHAEMetres (1, 3) double ...
        {mustBeFinite, mustBeStrictlyIncreasing}
    options.TargetProjectedMotionPixels (1, 1) double ...
        {mustBeFinite, mustBePositive} = 0.5
    options.ReferenceBand (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.MovingBand (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.ReferenceMask {mustBeMaskSource} = []
    options.MovingMask {mustBeMaskSource} = []
    options.DownsampleFactor (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 1
    options.ReferenceROI (1, :) double ...
        {mustBeOptionalNativeRoi} = zeros(1, 0)
    options.CoarseAdjustment (1, 1) string ...
        {mustBeMember(options.CoarseAdjustment, ...
        ["none", "symmetric-feature"])} = "none"
    options.FeatureDownsampleFactor (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 24
    options.MaximumFeatures (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive, ...
        mustBeAtMost250} = 250
    options.FeatureHeightSampleCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeGreaterThanOrEqual(options.FeatureHeightSampleCount, 3)} = 17
    options.ExecutionMode (1, 1) string ...
        {mustBeMember(options.ExecutionMode, ...
        ["direct", "hierarchical"])} = "direct"
    options.OverviewDownsampleFactor (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.OverviewTargetProjectedMotionPixels (1, 1) double ...
        {mustBeFinite, mustBePositive} = 1
    options.Display (1, 1) logical = true
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.MaximumPendingTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 8
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
    options.MinimumSupportFraction (1, 1) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.MinimumSupportFraction, 0), ...
        mustBeLessThanOrEqual(options.MinimumSupportFraction, 1)} = 0.8
    options.DerivativeSigma (1, 1) double ...
        {mustBeFinite, mustBePositive} = 1
    options.IntegrationSigma (1, 1) double ...
        {mustBeFinite, mustBePositive} = 2
    options.DeltaHeightMetres (1, 1) double ...
        {mustBeFinite, mustBePositive} = 0.5
    options.GeometryGridSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBeGreaterThanOrEqual( ...
        options.GeometryGridSize, 2)} = [7, 7]
    options.CostCurveFractions (:, 2) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.CostCurveFractions, 0), ...
        mustBeLessThanOrEqual(options.CostCurveFractions, 1)} = ...
        [0.5,0.5; 0.25,0.25; 0.75,0.25; 0.25,0.75; 0.75,0.75]
    options.PenaltyPerMetre (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.02
    options.MaximumPenalty (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.2
    options.DirectionCount (1, 1) double ...
        {mustBeMember(options.DirectionCount, [4, 8])} = 8
    options.RetainCostVolumes (1, 1) logical = false
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
totalTimer = tic;
h = options.HeightRangeHAEMetres;

inputTimer = tic;
[referenceNative, referenceInput] = readBand( ...
    options.ReferenceImage, options.ReferenceBand);
[movingNative, movingInput] = readBand( ...
    options.MovingImage, options.MovingBand);
referenceMaskNative = readMask( ...
    options.ReferenceMask, size(referenceNative), "reference");
movingMaskNative = readMask( ...
    options.MovingMask, size(movingNative), "moving");
referenceROI = resolveNativeRoi(options.ReferenceROI, ...
    size(referenceNative));
referenceDenseNative = referenceNative( ...
    referenceROI(1):referenceROI(2), ...
    referenceROI(3):referenceROI(4));
referenceDenseMaskNative = referenceMaskNative( ...
    referenceROI(1):referenceROI(2), ...
    referenceROI(3):referenceROI(4));
inputSeconds = toc(inputTimer);

preprocessTimer = tic;
[reference, referenceValid, resampler] = preprocess( ...
    referenceDenseNative, referenceDenseMaskNative, ...
    options.DownsampleFactor, ...
    options.WorkingPrecision);
[moving, movingValid] = preprocess( ...
    movingNative, movingMaskNative, options.DownsampleFactor, ...
    options.WorkingPrecision);
referenceNativeCamera = Rpc00bCamera( ...
    options.ReferenceTre, size(referenceNative));
movingNativeCamera = Rpc00bCamera( ...
    options.MovingTre, size(movingNative));
preprocessSeconds = toc(preprocessTimer);
adjustmentTimer = tic;
if options.CoarseAdjustment == "symmetric-feature"
    [featureReference, featureReferenceValid] = preprocess( ...
        referenceNative, referenceMaskNative, ...
        options.FeatureDownsampleFactor, options.WorkingPrecision);
    [featureMoving, featureMovingValid] = preprocess( ...
        movingNative, movingMaskNative, ...
        options.FeatureDownsampleFactor, options.WorkingPrecision);
    featureReferenceCamera = RpcImageWindowCamera( ...
        referenceNativeCamera, fullNativeRoi(size(referenceNative)), ...
        DownsampleFactor=options.FeatureDownsampleFactor);
    featureMovingCamera = RpcImageWindowCamera( ...
        movingNativeCamera, fullNativeRoi(size(movingNative)), ...
        DownsampleFactor=options.FeatureDownsampleFactor);
    featureReferenceValid = featureReferenceValid ...
        & detectorCenterMask(featureReferenceCamera);
    featureMovingValid = featureMovingValid ...
        & detectorCenterMask(featureMovingCamera);
    featureHeights = unique([linspace(h(1), h(3), ...
        options.FeatureHeightSampleCount), h(2)]);
    adjustment = RpcSymmetricFeatureAdjustment.estimateFromImages( ...
        featureReference, featureMoving, featureReferenceCamera, ...
        featureMovingCamera, featureHeights, ...
        ReferenceValid=featureReferenceValid, ...
        MovingValid=featureMovingValid, ...
        MaximumFeatures=options.MaximumFeatures);
else
    adjustment = noAdjustment(options, h);
end
adjustmentSeconds = toc(adjustmentTimer);
referenceCorrectedCamera = RpcImageCorrectionCamera( ...
    referenceNativeCamera, ...
    adjustment.ReferenceParametersNativePixelsRadians);
movingCorrectedCamera = RpcImageCorrectionCamera( ...
    movingNativeCamera, ...
    adjustment.MovingParametersNativePixelsRadians);
referenceCamera = RpcImageWindowCamera( ...
    referenceCorrectedCamera, referenceROI, ...
    DownsampleFactor=options.DownsampleFactor);
movingCamera = RpcImageWindowCamera( ...
    movingCorrectedCamera, fullNativeRoi(size(movingNative)), ...
    DownsampleFactor=options.DownsampleFactor);
referenceValid = referenceValid & detectorCenterMask(referenceCamera);
movingValid = movingValid & detectorCenterMask(movingCamera);
geometry = HeightSweepGeometry(referenceCamera, movingCamera);

geometryTimer = tic;
geometryDiagnostic = diagnoseGeometry(geometry, h, ...
    options.GeometryGridSize, options.DeltaHeightMetres);
labelPolicy = heightLabels(h, geometryDiagnostic, ...
    options.TargetProjectedMotionPixels);
z = labelPolicy.HeightLabelsHAEMetres;
labelPolicy.EstimatedCostVolumeBytes = numel(reference) .* numel(z) ...
    .* bytesPerElement(options.WorkingPrecision);
labelPolicy.EstimatedCostVolumeMebibytes = ...
    labelPolicy.EstimatedCostVolumeBytes ./ 2^20;
geometrySeconds = toc(geometryTimer);

if options.ExecutionMode == "hierarchical"
    report = runHierarchicalMode(referenceNative, movingNative, ...
        reference, moving, referenceValid, movingValid, ...
        referenceCamera, movingCamera, referenceInput, movingInput, ...
        referenceROI, adjustment, geometryDiagnostic, ...
        inputSeconds, preprocessSeconds, adjustmentSeconds, ...
        geometrySeconds, options, totalTimer);
    printHierarchicalReport(report);
    clear cleanup
    return
end

fprintf("RPC label plan: %d labels, target %.3g px, " + ...
    "estimated single cost volume %.3f MiB.\n", ...
    labelPolicy.LabelCount, labelPolicy.TargetProjectedMotionPixels, ...
    labelPolicy.EstimatedCostVolumeMebibytes);

curve = HeightCostCurve(geometry, reference, moving, ...
    DerivativeSigma=options.DerivativeSigma, ...
    IntegrationSigma=options.IntegrationSigma, ...
    ReferenceValid=referenceValid, MovingValid=movingValid, ...
    PrepareGradients=false, WorkingPrecision=options.WorkingPrecision);
dense = DenseHeightSweep(curve);

znccTimer = tic;
raw = dense.runZnccOptimized(z, ...
    TileSize=options.TileSize, LabelBlockSize=options.LabelBlockSize, ...
    StoreCostVolumes=true, UseParallel=options.UseParallel, ...
    NumWorkers=options.NumWorkers, ...
    MaximumPendingTiles=options.MaximumPendingTiles, ...
    WorkingPrecision=options.WorkingPrecision, ...
    MinimumSupportFraction=options.MinimumSupportFraction, ...
    DeltaHeight=options.DeltaHeightMetres, ...
    Products=["LabelIndex", "BestCost", "SecondBestCost", ...
    "NeighborCosts", "Margin", "Curvature", "ValidLabelCount", ...
    "Observability", "Correspondence"]);
znccSeconds = toc(znccTimer);

refineTimer = tic;
refined = HeightSublabelRefiner.refine(z, raw.LabelIndex, ...
    raw.PreviousLabelCost, raw.BestCost, raw.NextLabelCost, ...
    ValidMask=raw.Valid);
refinedProjection = dense.projectHeightMap( ...
    refined.RefinedHeightMetres, refined.Valid, ...
    DeltaHeight=options.DeltaHeightMetres);
refineSeconds = toc(refineTimer);

sgmTimer = tic;
sgmFull = HeightSgm.aggregateVectorized(raw.CostVolume, z, ...
    PenaltyPerMetre=options.PenaltyPerMetre, ...
    MaximumPenalty=options.MaximumPenalty, ...
    DirectionCount=options.DirectionCount, StorePathCosts=false);
sgmProjection = dense.projectHeightMap( ...
    sgmFull.HeightMetres, sgmFull.Valid, ...
    DeltaHeight=options.DeltaHeightMetres);
sgmSeconds = toc(sgmTimer);

diagnosticTimer = tic;
points = representativePoints(referenceValid, ...
    options.CostCurveFractions);
costCurves = curve.evaluate(points, z, Channels="Zncc", ...
    MinimumSupportFraction=options.MinimumSupportFraction, ...
    DeltaHeight=options.DeltaHeightMetres);
alignment = alignmentResidual( ...
    curve.Reference.Image, curve.Moving, ...
    sgmProjection.CorrespondenceXY, sgmProjection.Valid);
labelDiagnostic = labelDiagnostics(raw, sgmFull, refined, labelPolicy);
[warnings, warningKinds] = collectWarnings( ...
    geometryDiagnostic, labelPolicy, labelDiagnostic);
diagnosticSeconds = toc(diagnosticTimer);

if options.RetainCostVolumes
    sgm = sgmFull;
else
    raw.CostVolume = zeros([size(reference), 0], ...
        options.WorkingPrecision);
    raw.CostVolumeByChannel = struct;
    raw.StoreCostVolumes = false;
    sgm = stripSgmVolumes(sgmFull);
end

figures = struct;
displayTimer = tic;
if options.Display
    figures = displayReport(referenceNative, movingNative, reference, ...
        moving, referenceValid, movingValid, geometry, h, z, labelPolicy, ...
        geometryDiagnostic, raw, refined, sgmFull, alignment, ...
        points, costCurves.Costs.Zncc);
end
displaySeconds = toc(displayTimer);

timing = table( ...
    [inputSeconds; preprocessSeconds; adjustmentSeconds; ...
    geometrySeconds; znccSeconds; ...
    refineSeconds; sgmSeconds; diagnosticSeconds; displaySeconds; ...
    toc(totalTimer)], ...
    RowNames=["Input"; "Preprocess"; "CoarseAdjustment"; ...
    "GeometryDiagnostic"; "RawZncc"; ...
    "SublabelAndProjection"; "FrozenSgmAndProjection"; ...
    "ResultDiagnostics"; "Display"; "Total"], VariableNames="Seconds");
memory = memoryDiagnostic(raw, sgmFull, alignment, options);
input = struct( ...
    "ReferenceIdentifier", referenceInput.Identifier, ...
    "MovingIdentifier", movingInput.Identifier, ...
    "ReferenceTreIdentifier", treIdentifier(options.ReferenceTre), ...
    "MovingTreIdentifier", treIdentifier(options.MovingTre), ...
    "ReferenceReader", referenceInput.Reader, ...
    "MovingReader", movingInput.Reader, ...
    "ReferenceBand", referenceInput.Band, ...
    "MovingBand", movingInput.Band, ...
    "ReferenceNativeSize", size(referenceNative), ...
    "MovingNativeSize", size(movingNative), ...
    "ReferenceROIYXNative1x", referenceROI, ...
    "ReferenceROINativeSize", size(referenceDenseNative), ...
    "ReferenceProcessedSize", size(reference), ...
    "MovingProcessedSize", size(moving), ...
    "StorageClass", "uint16", ...
    "IntensityConversion", ...
    "native uint16 divided by 65535 at matching boundary", ...
    "DownsampleFactor", options.DownsampleFactor, ...
    "Resampler", resampler, ...
    "ProcessedToFullPixelMap", ...
    "pFull=[xStart-1,yStart-1]+s*(pROI-0.5)+0.5", ...
    "FullToProcessedPixelMap", ...
    "pROI=(pFull-[xStart-1,yStart-1]-0.5)/s+0.5");
settings = struct( ...
    "HeightRangeHAEMetres", h, ...
    "HeightLabelsHAEMetres", z, ...
    "HeightLabelCount", numel(z), ...
    "TargetProjectedMotionPixels", ...
    options.TargetProjectedMotionPixels, ...
    "ExecutionMode", options.ExecutionMode, ...
    "CoarseAdjustment", options.CoarseAdjustment, ...
    "FeatureDownsampleFactor", options.FeatureDownsampleFactor, ...
    "MaximumFeatures", options.MaximumFeatures, ...
    "ElevationDatum", referenceCamera.ElevationDatum, ...
    "WorldFrame", referenceCamera.WorldFrame, ...
    "PixelConvention", ...
    "one-based [x,y]=[sample,line]=[column,row] pixel centers", ...
    "TileSize", options.TileSize, ...
    "LabelBlockSize", options.LabelBlockSize, ...
    "WorkingPrecision", options.WorkingPrecision, ...
    "MinimumSupportFraction", options.MinimumSupportFraction, ...
    "PenaltyPerMetre", options.PenaltyPerMetre, ...
    "MaximumPenalty", options.MaximumPenalty, ...
    "DirectionCount", options.DirectionCount, ...
    "UseParallel", options.UseParallel, ...
    "NumWorkers", raw.Runtime.NumWorkers, ...
    "CostVolumesRetained", options.RetainCostVolumes);
cameraDiagnostic = struct( ...
    "Reference", safeCameraDiagnostic(referenceCamera), ...
    "Moving", safeCameraDiagnostic(movingCamera), ...
    "PrivateRpcFieldsEmbedded", false);
summary = safeSummary(input, settings, cameraDiagnostic, geometryDiagnostic, ...
    labelPolicy, labelDiagnostic, timing, memory, warnings, warningKinds, ...
    safeAdjustment(adjustment));

report = struct( ...
    "Purpose", ...
    "RPC00B normal-label smoke test; not a production RPC workflow", ...
    "Input", input, ...
    "Settings", settings, ...
    "Camera", cameraDiagnostic, ...
    "ProcessedReferenceImage", reference, ...
    "ProcessedMovingImage", moving, ...
    "ReferenceValid", referenceValid, ...
    "MovingValid", movingValid, ...
    "Geometry", geometryDiagnostic, ...
    "LabelPolicy", labelPolicy, ...
    "CoarseAdjustment", adjustment, ...
    "CostCurves", struct("ReferencePixelXY", points, ...
    "HeightLabelsHAEMetres", z, "Zncc", costCurves.Costs.Zncc), ...
    "RawZncc", raw, ...
    "Sublabel", refined, ...
    "SublabelProjection", refinedProjection, ...
    "FrozenSgm", sgm, ...
    "FrozenSgmProjection", sgmProjection, ...
    "Alignment", alignment, ...
    "LabelDiagnostics", labelDiagnostic, ...
    "Timing", timing, ...
    "Memory", memory, ...
    "Warnings", warnings, ...
    "WarningKinds", warningKinds, ...
    "Summary", summary, ...
    "SummaryIsRedactionSafe", true, ...
    "FullReportContainsDerivedImageData", true, ...
    "Figures", figures);

printReport(report);
clear cleanup
end

function report = runHierarchicalMode(referenceNative, movingNative, ...
        reference, moving, referenceValid, movingValid, ...
        referenceCamera, movingCamera, referenceInput, movingInput, ...
        referenceROI, adjustment, geometryDiagnostic, inputSeconds, ...
        preprocessSeconds, adjustmentSeconds, geometrySeconds, options, ...
        totalTimer)
%RUNHIERARCHICALMODE Existing C1 hierarchy through corrected RPC wrappers.
% Traceability: long-range workplan C1; algo/main.tex Algorithm 1.
h = options.HeightRangeHAEMetres;
s = options.DownsampleFactor;
if options.OverviewDownsampleFactor == 0
    overviewAbsolute = s .* max(2, ceil(24 ./ s));
else
    overviewAbsolute = options.OverviewDownsampleFactor;
end
if overviewAbsolute <= s || mod(overviewAbsolute, s) ~= 0
    error("runRpc00bHeightTest:InvalidOverviewFactor", ...
        "OverviewDownsampleFactor must be an integer multiple greater than DownsampleFactor.");
end
relativeFactor = overviewAbsolute ./ s;
solver = HierarchicalHeightSolver(referenceCamera, movingCamera, ...
    reference, moving, ReferenceValid=referenceValid, ...
    MovingValid=movingValid, PyramidFactors=[relativeFactor, 1], ...
    WorkingPrecision=options.WorkingPrecision);

overviewTimer = tic;
overview = solver.runOverview(h([1, 3]), ...
    TargetProjectedMotionPixels= ...
    options.OverviewTargetProjectedMotionPixels, ...
    GeometrySampleGrid=max(options.GeometryGridSize, 3), ...
    DeltaHeightMetres=options.DeltaHeightMetres, ...
    TileSize=options.TileSize, LabelBlockSize=options.LabelBlockSize, ...
    MinimumSupportFraction=options.MinimumSupportFraction, ...
    PenaltyPerMetre=options.PenaltyPerMetre, ...
    MaximumPenalty=options.MaximumPenalty, ...
    DirectionCount=options.DirectionCount, ...
    UseParallel=options.UseParallel, NumWorkers=options.NumWorkers, ...
    MaximumPendingTiles=options.MaximumPendingTiles, ...
    RetainCostVolume=options.RetainCostVolumes);
overviewSeconds = toc(overviewTimer);

planningTimer = tic;
calibrator = HeightConfidenceCalibrator(0.1, 0.1, zeros(1, 0), 1);
plan = solver.prepareNextLevel(overview, calibrator, ...
    TargetProjectedMotionPixels=options.TargetProjectedMotionPixels, ...
    TileSize=options.TileSize, GeometrySampleGrid=[3, 3], ...
    DeltaHeightMetres=options.DeltaHeightMetres, ...
    LowConfidenceSigmaPixels=0.5, ...
    ConfidenceSigmaMultiplier=1);
planningSeconds = toc(planningTimer);

fineTimer = tic;
fine = solver.runFineAdaptive(plan, ...
    LabelBlockSize=options.LabelBlockSize, ...
    GroupIdenticalBands=true, MaximumBandTiles=4, ...
    MinimumSupportFraction=options.MinimumSupportFraction, ...
    DeltaHeightMetres=options.DeltaHeightMetres, RunSgm=true, ...
    PenaltyPerMetre=options.PenaltyPerMetre, ...
    MaximumPenalty=options.MaximumPenalty, ...
    DirectionCount=options.DirectionCount, ...
    RetainCostVolumes=options.RetainCostVolumes, ...
    UseParallel=options.UseParallel, NumWorkers=options.NumWorkers, ...
    MaximumPendingTiles=options.MaximumPendingTiles);
fineSeconds = toc(fineTimer);

diagnosticTimer = tic;
alignment = alignmentResidualArrays(reference, moving, ...
    movingValid, fine.Sgm.CorrespondenceXY, fine.Sgm.Valid);
diagnostic = hierarchyDiagnostics(overview, fine);
diagnosticSeconds = toc(diagnosticTimer);

figures = struct;
displayTimer = tic;
if options.Display
    figures = displayHierarchy(referenceNative, movingNative, ...
        reference, moving, referenceValid, movingValid, overview, fine, ...
        alignment, h, adjustment);
end
displaySeconds = toc(displayTimer);

timing = table([inputSeconds; preprocessSeconds; adjustmentSeconds; ...
    geometrySeconds; overviewSeconds; planningSeconds; fineSeconds; ...
    diagnosticSeconds; displaySeconds; toc(totalTimer)], ...
    RowNames=["Input"; "Preprocess"; "CoarseAdjustment"; ...
    "GeometryDiagnostic"; "Overview"; "FinePlanning"; ...
    "AdaptiveFineAndSgm"; "ResultDiagnostics"; "Display"; "Total"], ...
    VariableNames="Seconds");
input = struct( ...
    "ReferenceIdentifier", referenceInput.Identifier, ...
    "MovingIdentifier", movingInput.Identifier, ...
    "ReferenceTreIdentifier", treIdentifier(options.ReferenceTre), ...
    "MovingTreIdentifier", treIdentifier(options.MovingTre), ...
    "ReferenceBand", referenceInput.Band, ...
    "MovingBand", movingInput.Band, ...
    "ReferenceNativeSize", size(referenceNative), ...
    "MovingNativeSize", size(movingNative), ...
    "ReferenceROIYXNative1x", referenceROI, ...
    "ReferenceROINativeSize", ...
    [referenceROI(2) - referenceROI(1) + 1, ...
    referenceROI(4) - referenceROI(3) + 1], ...
    "ReferenceProcessedSize", size(reference), ...
    "MovingProcessedSize", size(moving), ...
    "DownsampleFactor", s, ...
    "OverviewDownsampleFactor", overviewAbsolute, ...
    "ProcessedToFullPixelMap", ...
    "pFull=[xStart-1,yStart-1]+s*(pROI-0.5)+0.5");
settings = struct( ...
    "ExecutionMode", "hierarchical", ...
    "HeightRangeHAEMetres", h, ...
    "DownsampleFactor", s, ...
    "OverviewDownsampleFactor", overviewAbsolute, ...
    "RelativePyramidFactors", [relativeFactor, 1], ...
    "OverviewTargetProjectedMotionPixels", ...
    options.OverviewTargetProjectedMotionPixels, ...
    "FineTargetProjectedMotionPixels", ...
    options.TargetProjectedMotionPixels, ...
    "CoarseAdjustment", options.CoarseAdjustment, ...
    "WorkingPrecision", options.WorkingPrecision, ...
    "TileSize", options.TileSize, ...
    "LabelBlockSize", options.LabelBlockSize, ...
    "PenaltyPerMetre", options.PenaltyPerMetre, ...
    "MaximumPenalty", options.MaximumPenalty, ...
    "DirectionCount", options.DirectionCount, ...
    "UseParallel", options.UseParallel, ...
    "NumWorkers", fine.Raw.Runtime.NumWorkers, ...
    "ConfidencePlanningPolicy", ...
    "provisional fixed 1-pixel sigma; warnings expand local bands");
camera = struct("Reference", safeCameraDiagnostic(referenceCamera), ...
    "Moving", safeCameraDiagnostic(movingCamera), ...
    "PrivateRpcFieldsEmbedded", false);
labelPolicy = struct( ...
    "OverviewLabelsHAEMetres", overview.HeightLabelsMetres, ...
    "OverviewLabelCount", numel(overview.HeightLabelsMetres), ...
    "FineTileCount", size(fine.FinalTilePlan, 1), ...
    "FineMinimumLabelCount", min(fine.FinalTilePlan.LabelCount), ...
    "FineMedianLabelCount", median(fine.FinalTilePlan.LabelCount), ...
    "FineMaximumLabelCount", max(fine.FinalTilePlan.LabelCount), ...
    "FineEvaluatedPixelLabelCount", fine.Runtime.EvaluatedPixelLabelCount, ...
    "Definition", ...
    "one exact overview grid then one local grid per tile with one expansion pass");
memory = struct( ...
    "OverviewCostVolumeBytes", overview.Runtime.CostVolumeBytes, ...
    "FineCostVolumeBytes", NaN, ...
    "PeakResidentBytes", NaN, ...
    "Definition", ...
    "overview tracked payload; adaptive in-memory tile payload not process RSS");
summary = struct( ...
    "Purpose", "RPC00B adjusted hierarchical smoke test", ...
    "ReferenceIdentifier", input.ReferenceIdentifier, ...
    "MovingIdentifier", input.MovingIdentifier, ...
    "ReferenceNativeSize", input.ReferenceNativeSize, ...
    "MovingNativeSize", input.MovingNativeSize, ...
    "ReferenceROIYXNative1x", referenceROI, ...
    "ReferenceProcessedSize", size(reference), ...
    "MovingProcessedSize", size(moving), ...
    "Settings", settings, "Camera", camera, ...
    "CoarseAdjustment", safeAdjustment(adjustment), ...
    "GeometryPerHeight", geometryDiagnostic.PerHeight, ...
    "LabelPolicy", labelPolicy, "Diagnostics", diagnostic, ...
    "Timing", timing, "Memory", memory, ...
    "ContainsTrePayloadOrCoefficients", false, ...
    "ContainsGeographicCoordinates", false, ...
    "ContainsRasterPixels", false);
report = struct( ...
    "Purpose", "RPC00B adjusted hierarchical smoke test", ...
    "Input", input, "Settings", settings, "Camera", camera, ...
    "CoarseAdjustment", adjustment, "Geometry", geometryDiagnostic, ...
    "LabelPolicy", labelPolicy, "Overview", overview, ...
    "FinePlan", plan, "Fine", fine, ...
    "RawZncc", fine.Raw, "Sublabel", fine.Refined, ...
    "FrozenSgm", fine.Sgm, "Alignment", alignment, ...
    "Diagnostics", diagnostic, "Timing", timing, "Memory", memory, ...
    "ProcessedReferenceImage", reference, ...
    "ProcessedMovingImage", moving, ...
    "ReferenceValid", referenceValid, "MovingValid", movingValid, ...
    "Summary", summary, "SummaryIsRedactionSafe", true, ...
    "FullReportContainsDerivedImageData", true, "Figures", figures);
end

function result = hierarchyDiagnostics(overview, fine)
rawValid = nnz(fine.Raw.Valid);
sgmValid = nnz(fine.Sgm.Valid);
result = struct( ...
    "OverviewRawBoundaryFraction", ...
    overview.Warnings.RawBoundaryWinnerFraction, ...
    "OverviewSgmBoundaryFraction", ...
    overview.Warnings.SgmBoundaryWinnerFraction, ...
    "FineRawValidFraction", mean(fine.Raw.Valid, "all"), ...
    "FineSgmValidFraction", mean(fine.Sgm.Valid, "all"), ...
    "FineRawBoundaryFraction", ...
    nnz(fine.Warnings.FinalBoundaryWinner) ./ max(rawValid, 1), ...
    "FineSgmBoundaryFraction", ...
    nnz(fine.Warnings.FinalSgmBoundaryWinner) ./ max(sgmValid, 1), ...
    "ExpandedTileCount", fine.Runtime.ExpandedTileCount, ...
    "EvaluatedPixelLabelCount", fine.Runtime.EvaluatedPixelLabelCount, ...
    "Approximation", fine.Approximation);
end

function result = alignmentResidualArrays(reference, moving, movingValid, ...
        correspondence, valid)
x = correspondence(:, :, 1);
y = correspondence(:, :, 2);
warped = interp2(moving, x, y, "linear", NaN);
weight = interp2(single(movingValid), x, y, "linear", 0);
inside = valid & isfinite(warped) & weight >= 1 - 64 .* eps("single");
warped(~inside) = NaN;
residual = reference - warped;
residual(~inside) = NaN;
v = residual(inside);
result = struct("WarpedMovingImage", warped, ...
    "ReferenceMinusWarpedMoving", residual, "Valid", inside, ...
    "ReferenceMovingOverlayRGB", ...
    alignmentOverlay(reference, warped, inside), ...
    "ValidFraction", mean(inside, "all"), ...
    "ResidualMean", finiteStatistic(v, @mean), ...
    "ResidualRms", sqrt(finiteStatistic(v .^ 2, @mean)), ...
    "Definition", "moving intensity sampled at final hierarchical SGM correspondence");
end

