function [image, info] = readBand(file, band)
[~, name, extension] = fileparts(file);
extension = lower(string(extension));
if any(extension == [".ntf", ".nitf"])
    if exist("nitfread", "file") ~= 2
        error("runRpc00bHeightTest:NitfReaderUnavailable", ...
            "Reading NITF input requires nitfread from Image Processing Toolbox.");
    end
    metadata = nitfinfo(file);
    if ~isfield(metadata, "NumberOfImages") ...
            || str2double(string(metadata.NumberOfImages)) ~= 1
        error("runRpc00bHeightTest:SegmentedNitfUnsupported", ...
            ["Phase B0 requires one raster covering the complete RPC image. " ...
            "Segment mosaicking and segment-origin transforms are deferred."]);
    end
    raster = nitfread(char(file), 1);
    reader = "nitfread single full-image segment";
else
    raster = imread(file);
    reader = "imread";
end
if ~isa(raster, "uint16")
    error("runRpc00bHeightTest:Uint16Required", ...
        "Input %s must be uint16; received %s.", name, class(raster));
end
if ismatrix(raster)
    if band > 1
        error("runRpc00bHeightTest:BandOutOfRange", ...
            "Single-channel input %s accepts band 0 or 1.", name);
    end
    selectedBand = 1;
    image = raster;
elseif ndims(raster) == 3
    if band == 0
        error("runRpc00bHeightTest:BandRequired", ...
            "Multiband input %s requires an explicit one-based band.", name);
    end
    if band > size(raster, 3)
        error("runRpc00bHeightTest:BandOutOfRange", ...
            "Requested band %d exceeds the %d bands in %s.", ...
            band, size(raster, 3), name);
    end
    selectedBand = band;
    image = raster(:, :, band);
else
    error("runRpc00bHeightTest:UnsupportedRasterShape", ...
        "Input %s must be a two- or three-dimensional raster.", name);
end
info = struct("Identifier", string(name + extension), ...
    "Reader", reader, "Band", selectedBand);
end

function roi = resolveNativeRoi(value, imageSize)
if isempty(value)
    roi = fullNativeRoi(imageSize);
else
    roi = value;
end
if roi(2) > imageSize(1) || roi(4) > imageSize(2) ...
        || roi(2) < roi(1) || roi(4) < roi(3)
    error("runRpc00bHeightTest:InvalidReferenceROI", ...
        "ReferenceROI must be inclusive, one-based native 1x " ...
        + "[yStart,yEnd,xStart,xEnd] inside the reference raster.");
end
end

function roi = fullNativeRoi(imageSize)
roi = [1, imageSize(1), 1, imageSize(2)];
end

function result = noAdjustment(options, h)
result = struct( ...
    "Model", "none", ...
    "ReferenceParametersNativePixelsRadians", [0, 0, 0], ...
    "MovingParametersNativePixelsRadians", [0, 0, 0], ...
    "Gauge", "no correction", ...
    "HeightSamplesHAEMetres", h, ...
    "CandidateCount", 0, "InlierCount", 0, ...
    "BeforeMedianResidualPixels", NaN, ...
    "AfterMedianResidualPixels", NaN, ...
    "Iterations", 0, "NormalMatrixCondition", NaN, ...
    "Converged", true, ...
    "MaximumFeaturesPerImage", options.MaximumFeatures, ...
    "ReferenceFeatureFactor", options.FeatureDownsampleFactor, ...
    "MovingFeatureFactor", options.FeatureDownsampleFactor, ...
    "Limitation", "feature adjustment disabled by caller");
end

function mask = readMask(source, imageSize, role)
if isempty(source)
    mask = true(imageSize);
elseif islogical(source)
    mask = source;
else
    raw = imread(string(source));
    if ~ismatrix(raw)
        error("runRpc00bHeightTest:MaskChannels", ...
            "The %s mask must be single channel.", role);
    end
    mask = raw ~= 0;
end
if ~isequal(size(mask), imageSize)
    error("runRpc00bHeightTest:MaskSizeMismatch", ...
        "The %s mask must match its native selected image band.", role);
end
end

function [image, mask, description] = preprocess( ...
        native, nativeMask, factor, precision)
if factor == 1
    resized = native;
    mask = nativeMask;
    description = "none; factor 1 identity";
else
    if exist("imresize", "file") ~= 2
        error("runRpc00bHeightTest:ImageResizerUnavailable", ...
            "DownsampleFactor greater than one requires imresize.");
    end
    resized = imresize(native, 1 ./ factor, "bilinear", ...
        "Antialiasing", true);
    maskWeight = imresize(single(nativeMask), 1 ./ factor, "bilinear", ...
        "Antialiasing", true);
    mask = maskWeight >= 1 - 64 .* eps("single");
    description = "imresize bilinear with Antialiasing=true";
end
image = cast(resized, precision) ./ cast(intmax("uint16"), precision);
end

function mask = detectorCenterMask(camera)
[y, x] = ndgrid(1:camera.ImageSize(1), 1:camera.ImageSize(2));
mask = reshape(camera.isInsideImage([x(:), y(:)]), camera.ImageSize);
end

function result = diagnoseGeometry(geometry, z, gridSize, deltaHeight)
sz = geometry.ReferenceCamera.ImageSize;
[y, x] = ndgrid(linspace(1, sz(1), gridSize(1)), ...
    linspace(1, sz(2), gridSize(2)));
p = [x(:), y(:)];
n = size(p, 1);
w = nan(n, 2, 3);
valid = false(n, 3);
inside = false(n, 3);
derivativeValid = false(n, 3);
inverseConverged = false(n, 3);
kappa = nan(n, 3);
iterations = nan(n, 3);
inverseResidual = nan(n, 3);
roundTrip = nan(n, 3);
for k = 1:3
    [world, vr, d] = geometry.ReferenceCamera.imageToWorldAtHeight(p, z(k));
    [pr, vp] = geometry.ReferenceCamera.worldToImage(world);
    [w(:, :, k), vw, inside(:, k)] = geometry.warp(p, z(k));
    [~, kappa(:, k), vd] = geometry.heightDerivative( ...
        p, z(k), DeltaHeight=deltaHeight);
    valid(:, k) = vr & vp & vw;
    derivativeValid(:, k) = vd;
    inverseConverged(:, k) = nestedDiagnostic(d, "Converged");
    iterations(:, k) = nestedDiagnostic(d, "Iterations");
    inverseResidual(:, k) = nestedDiagnostic(d, "ResidualPixels");
    roundTrip(:, k) = vecnorm(pr - p, 2, 2);
end

d12 = w(:, :, 2) - w(:, :, 1);
d23 = w(:, :, 3) - w(:, :, 2);
m12 = vecnorm(d12, 2, 2);
m23 = vecnorm(d23, 2, 2);
denominator = vecnorm(d12, 2, 2) .* vecnorm(d23, 2, 2);
direction = acosd(max(-1, min(1, sum(d12 .* d23, 2) ./ denominator)));
direction(~isfinite(direction)) = NaN;
perHeight = table(z(:), mean(inverseConverged, 1).', ...
    mean(valid, 1).', mean(inside, 1).', mean(derivativeValid, 1).', ...
    columnStatistic(kappa, @median), ...
    columnPercentile(kappa, 95), ...
    columnStatistic(iterations, @median), ...
    columnStatistic(inverseResidual, @max), ...
    columnStatistic(roundTrip, @max), ...
    VariableNames=["HeightHAEMetres", "RpcInverseConvergedFraction", ...
    "GeometricValidFraction", "InsideMovingFraction", ...
    "DerivativeValidFraction", "MedianDwDzPixelsPerMetre", ...
    "P95DwDzPixelsPerMetre", "MedianInverseIterations", ...
    "MaximumInverseResidualPixels", "MaximumRoundTripResidualPixels"]);
result = struct( ...
    "ReferencePixelXY", p, ...
    "MovingTrajectoryXY", w, ...
    "GeometricValid", valid, ...
    "InsideMoving", inside, ...
    "DerivativeValid", derivativeValid, ...
    "InverseNonconverged", ~inverseConverged, ...
    "DwDzPixelsPerMetre", kappa, ...
    "PerHeight", perHeight, ...
    "AdjacentMotionPixels", [m12, m23], ...
    "AdjacentMotionMedianPixels", ...
    [finiteStatistic(m12, @median), finiteStatistic(m23, @median)], ...
    "AdjacentMotionP95Pixels", ...
    [finitePercentile(m12, 95), finitePercentile(m23, 95)], ...
    "TotalTrajectoryMedianPixels", ...
    finiteStatistic(m12 + m23, @median), ...
    "DirectionChangeDegrees", direction, ...
    "MedianDirectionChangeDegrees", finiteStatistic(direction, @median), ...
    "HeightDerivativeStepMetres", deltaHeight, ...
    "SampleGridSize", gridSize, ...
    "Definition", ...
    "exact RPC warp at supplied HAE; central finite-difference dw/dz");
end

function policy = heightLabels(h, geometry, target)
%HEIGHTLABELS P1 fine-grid policy from measured RPC observability.
% Traceability: algo/main.tex Eq. (55), Secs. 10.4 and 11.2; P1 frozen
% 0.5-pixel fine-label policy. The expected HAE anchor is retained exactly.
kappa = geometry.DwDzPixelsPerMetre;
valid = geometry.DerivativeValid & isfinite(kappa) & kappa > 0;
if ~any(valid, "all")
    error("runRpc00bHeightTest:NoObservableGeometry", ...
        "No valid positive RPC dw/dz samples are available for label spacing.");
end
medianKappa = median(kappa(valid));
n = max(1, ceil(diff(h) .* medianKappa ./ target));
lower = linspace(h(1), h(2), n(1) + 1);
upper = linspace(h(2), h(3), n(2) + 1);
z = [lower, upper(2:end)];
motion = diff(z) .* medianKappa;
policy = struct( ...
    "HeightRangeHAEMetres", h, ...
    "ExpectedHeightHAEMetres", h(2), ...
    "HeightLabelsHAEMetres", z, ...
    "ExpectedLabelIndex", numel(lower), ...
    "LabelCount", numel(z), ...
    "SegmentIntervalCounts", n, ...
    "TargetProjectedMotionPixels", target, ...
    "MedianObservabilityPixelsPerMetre", medianKappa, ...
    "P10ObservabilityPixelsPerMetre", ...
    finitePercentile(kappa(valid), 10), ...
    "P90ObservabilityPixelsPerMetre", ...
    finitePercentile(kappa(valid), 90), ...
    "AdjacentMedianProjectedMotionPixels", motion, ...
    "MaximumAdjacentMedianProjectedMotionPixels", max(motion), ...
    "Definition", ...
    "separate uniform min-to-expected and expected-to-max grids from median valid RPC ||dw/dz||");
end

function points = representativePoints(mask, fractions)
[yValid, xValid] = find(mask);
if isempty(xValid)
    error("runRpc00bHeightTest:NoValidReferencePixels", ...
        "The processed reference image contains no valid pixels.");
end
target = 1 + fractions .* ([size(mask, 2), size(mask, 1)] - 1);
points = zeros(size(target));
for k = 1:size(target, 1)
    [~, id] = min((xValid - target(k, 1)) .^ 2 ...
        + (yValid - target(k, 2)) .^ 2);
    points(k, :) = [xValid(id), yValid(id)];
end
points = unique(points, "rows", "stable");
end

function result = alignmentResidual(reference, moving, correspondence, valid)
resultWarped = nan(size(reference), "like", reference);
resultValid = false(size(reference));
index = find(valid);
if ~isempty(index)
    x = correspondence(:, :, 1);
    y = correspondence(:, :, 2);
    [sample, sampleValid] = moving.sampleIntensity([x(index), y(index)]);
    keep = index(sampleValid);
    resultWarped(keep) = sample(sampleValid);
    resultValid(keep) = true;
end
residual = reference - resultWarped;
residual(~resultValid) = NaN;
finiteResidual = residual(resultValid & isfinite(residual));
overlay = alignmentOverlay(reference, resultWarped, resultValid);
result = struct( ...
    "WarpedMovingImage", resultWarped, ...
    "ReferenceMinusWarpedMoving", residual, ...
    "ReferenceMovingOverlayRGB", overlay, ...
    "Valid", resultValid, ...
    "ValidFraction", mean(resultValid, "all"), ...
    "MeanAbsoluteResidual", finiteStatistic(abs(finiteResidual), @mean), ...
    "RootMeanSquareResidual", ...
    sqrt(finiteStatistic(finiteResidual .^ 2, @mean)), ...
    "Definition", "reference intensity minus SGM-selected warped moving");
end

function rgb = alignmentOverlay(reference, warped, valid)
samples = [reference(valid); warped(valid)];
lo = finitePercentile(samples, 1);
hi = finitePercentile(samples, 99);
scale = max(hi - lo, eps(class(reference)));
r = min(max((reference - lo) ./ scale, 0), 1);
m = min(max((warped - lo) ./ scale, 0), 1);
r(~valid) = 0;
m(~valid) = 0;
rgb = cat(3, r, m, r);
end

function result = labelDiagnostics(raw, sgm, refined, policy)
z = policy.HeightLabelsHAEMetres;
n = numel(z);
names = ["raw-ZNCC"; "frozen-SGM"];
index = {raw.LabelIndex; sgm.LabelIndex};
valid = {raw.Valid; sgm.Valid};
fraction = zeros(n, 2);
validFraction = zeros(2, 1);
boundaryFraction = zeros(2, 1);
expectedFraction = zeros(2, 1);
for k = 1:2
    validFraction(k) = mean(valid{k}, "all");
    denominator = nnz(valid{k});
    if denominator > 0
        selected = double(index{k}(valid{k}));
        fraction(:, k) = accumarray(selected, 1, [n, 1]) ./ denominator;
        boundaryFraction(k) = mean(selected == 1 | selected == n);
        expectedFraction(k) = mean( ...
            selected == policy.ExpectedLabelIndex);
    end
end
labelIndex = (1:n).';
isBoundary = labelIndex == 1 | labelIndex == n;
isExpected = labelIndex == policy.ExpectedLabelIndex;
selection = table(labelIndex, z(:), isBoundary, isExpected, ...
    fraction(:, 1), fraction(:, 2), ...
    VariableNames=["LabelIndex", "HeightHAEMetres", "IsBoundary", ...
    "IsExpectedHeight", "RawZnccFraction", "FrozenSgmFraction"]);
methodSummary = table(names, validFraction, boundaryFraction, ...
    expectedFraction, VariableNames=["Method", "ValidFraction", ...
    "BoundaryFraction", "ExpectedHeightFraction"]);
rawBoundary = raw.Valid & (raw.LabelIndex == 1 | raw.LabelIndex == n);
sgmBoundary = sgm.Valid & (sgm.LabelIndex == 1 | sgm.LabelIndex == n);
result = struct( ...
    "HeightLabelsHAEMetres", z, ...
    "SelectionFractions", selection, ...
    "MethodSummary", methodSummary, ...
    "RawBoundaryWinner", rawBoundary, ...
    "SgmBoundaryWinner", sgmBoundary, ...
    "RawBoundaryFraction", nnz(rawBoundary) ./ max(nnz(raw.Valid), 1), ...
    "SgmBoundaryFraction", nnz(sgmBoundary) ./ max(nnz(sgm.Valid), 1), ...
    "RefinementValidFractionOfRaw", ...
    nnz(refined.Valid) ./ max(nnz(raw.Valid), 1), ...
    "AdjacentSgmPenalty", diag(sgm.PairwisePenalty, 1).', ...
    "Definition", ...
    "per-label WTA fractions on the generated normal HAE grid");
end

function [warnings, kinds] = collectWarnings(geometry, policy, labels)
warnings = strings(10, 1);
kinds = strings(10, 1);
count = 0;
motion = geometry.AdjacentMotionMedianPixels;
for k = 1:2
    if isfinite(motion(k)) && motion(k) > 64
        count = count + 1;
        warnings(count) = ...
            "HAE range anchors " + k + " and " + (k + 1) ...
            + " span more than 64 pixels at the median sample.";
        kinds(count) = "height-range-motion-large";
    end
end
if policy.MaximumAdjacentMedianProjectedMotionPixels ...
        > policy.TargetProjectedMotionPixels .* (1 + 64 .* eps)
    count = count + 1;
    warnings(count) = ...
        "Generated label motion exceeds the requested median target.";
    kinds(count) = "label-spacing-large";
end
if policy.P90ObservabilityPixelsPerMetre ...
        > 2 .* policy.MedianObservabilityPixelsPerMetre
    count = count + 1;
    warnings(count) = ...
        "P90 RPC height observability exceeds twice the median; local label motion may be under-dense.";
    kinds(count) = "observability-variation";
end
if min(geometry.PerHeight.InsideMovingFraction) < 0.5
    count = count + 1;
    warnings(count) = ...
        "Fewer than half of sampled trajectories are inside the moving image at one or more heights.";
    kinds(count) = "geometry-bounds";
end
if min(geometry.PerHeight.RpcInverseConvergedFraction) < 1
    count = count + 1;
    warnings(count) = ...
        "One or more sampled reference RPC inversions did not converge.";
    kinds(count) = "rpc-inversion";
end
if min(geometry.PerHeight.DerivativeValidFraction) < 0.5
    count = count + 1;
    warnings(count) = ...
        "Fewer than half of sampled dw/dz evaluations are valid at one or more heights.";
    kinds(count) = "height-derivative";
end
if max(geometry.PerHeight.MaximumInverseResidualPixels) > 1e-5
    count = count + 1;
    warnings(count) = ...
        "Sampled RPC inverse residual exceeds 1e-5 pixels.";
    kinds(count) = "rpc-inversion";
end
if labels.RawBoundaryFraction > 0.5
    count = count + 1;
    warnings(count) = ...
        "More than half of valid raw ZNCC winners lie on a height-range boundary.";
    kinds(count) = "height-range-boundary";
end
if count == 0
    warnings = "No automatic diagnostic warnings.";
    kinds = "none";
else
    warnings = warnings(1:count);
    kinds = kinds(1:count);
end
end

function sgm = stripSgmVolumes(full)
keep = ["HeightLabelsMetres", "HeightMetres", "LabelIndex", ...
    "BestCost", "SecondBestCost", "CostMargin", "Valid", ...
    "PairwisePenalty", "PenaltyPerMetre", "MaximumPenalty", ...
    "PenaltyModel", "DirectionsYX", "DirectionCount", "Precision", ...
    "DirectionRuntimeSeconds", "TrackedArrayBytes", ...
    "MaximumScanlineStateBytes", "MemoryDefinition", "InvalidState", ...
    "Execution", "RuntimeSeconds"];
sgm = struct;
for k = 1:numel(keep)
    sgm.(keep(k)) = full.(keep(k));
end
sgm.CostVolumesRetained = false;
end

