result = struct( ...
    "RawZnccOutputBytes", raw.Runtime.OutputArrayBytes, ...
    "CostVolumeBytes", costBytes, ...
    "SgmTrackedArrayBytes", sgm.TrackedArrayBytes, ...
    "SgmMaximumScanlineStateBytes", sgm.MaximumScanlineStateBytes, ...
    "AlignmentArrayBytes", ...
    numel(alignment.WarpedMovingImage) ...
    .* bytesPerElement(class(alignment.WarpedMovingImage)) ...
    + numel(alignment.ReferenceMinusWarpedMoving) ...
    .* bytesPerElement(class(alignment.ReferenceMinusWarpedMoving)) ...
    + numel(alignment.ReferenceMovingOverlayRGB) ...
    .* bytesPerElement(class(alignment.ReferenceMovingOverlayRGB)) ...
    + numel(alignment.Valid), ...
    "CostVolumesRetained", options.RetainCostVolumes, ...
    "PeakResidentBytes", NaN, ...
    "Definition", ...
    "tracked MATLAB payload lower bounds; process peak resident unavailable");
end

