    "DownsampleFactor", input.DownsampleFactor, ...
    "HeightRangeHAEMetres", settings.HeightRangeHAEMetres, ...
    "HeightLabelsHAEMetres", settings.HeightLabelsHAEMetres, ...
    "HeightLabelCount", settings.HeightLabelCount, ...
    "TargetProjectedMotionPixels", ...
    settings.TargetProjectedMotionPixels, ...
    "LabelPolicy", policy, ...
    "ElevationDatum", settings.ElevationDatum, ...
    "Camera", camera, ...
    "CoarseAdjustment", adjustment, ...
    "GeometryPerHeight", geometry.PerHeight, ...
    "AdjacentMotionMedianPixels", geometry.AdjacentMotionMedianPixels, ...
    "MedianDirectionChangeDegrees", geometry.MedianDirectionChangeDegrees, ...
