    "MethodSummary", labels.MethodSummary, ...
    "RawBoundaryFraction", labels.RawBoundaryFraction, ...
    "SgmBoundaryFraction", labels.SgmBoundaryFraction, ...
    "RefinementValidFractionOfRaw", labels.RefinementValidFractionOfRaw, ...
    "Timing", timing, ...
    "Memory", memory, ...
    "Warnings", warnings, ...
    "WarningKinds", kinds, ...
    "ContainsTrePayloadOrCoefficients", false, ...
    "ContainsGeographicCoordinates", false, ...
    "ContainsRasterPixels", false);
end

function result = safeCameraDiagnostic(camera)
window = [];
correction = [];
if isa(camera, "RpcImageWindowCamera")
    window = struct("NativeROIYX", camera.NativeROI, ...
        "NativeWindowSize", camera.NativeWindowSize, ...
        "ProcessedImageSize", camera.ImageSize, ...
        "DownsampleFactor", camera.DownsampleFactor, ...
        "CoordinateMap", ...
        "pNative=origin+s*(pWorking-0.5)+0.5");
    camera = camera.BaseCamera;
end
if isa(camera, "RpcImageCorrectionCamera")
    correction = struct("ParametersNativePixelsRadians", ...
        camera.Parameters, "RotationCenterXY", camera.RotationCenterXY, ...
        "CoordinateMap", ...
        "pCorrected=R*(pBase-center)+center+[dx,dy]");
    camera = camera.BaseCamera;
end
result = struct( ...
    "Model", "RPC00B", ...
    "TreSourceKind", camera.TreSourceKind, ...
    "Success", camera.Success, ...
    "ErrorBiasMetres", camera.ErrorBiasMetres, ...
    "ErrorRandomMetres", camera.ErrorRandomMetres, ...
    "FullImageSize", camera.FullImageSize, ...
    "ProcessedImageSize", camera.ImageSize, ...
    "DownsampleFactor", camera.DownsampleFactor, ...
    "Window", window, "Correction", correction, ...
    "CoefficientPayloadEmbedded", false);
end

function result = safeAdjustment(adjustment)
result = struct( ...
    "Model", adjustment.Model, ...
    "ReferenceParametersNativePixelsRadians", ...
    adjustment.ReferenceParametersNativePixelsRadians, ...
    "MovingParametersNativePixelsRadians", ...
    adjustment.MovingParametersNativePixelsRadians, ...
    "Gauge", adjustment.Gauge, ...
    "CandidateCount", adjustment.CandidateCount, ...
    "InlierCount", adjustment.InlierCount, ...
    "BeforeMedianResidualPixels", ...
    adjustment.BeforeMedianResidualPixels, ...
    "AfterMedianResidualPixels", ...
    adjustment.AfterMedianResidualPixels, ...
    "Iterations", adjustment.Iterations, ...
    "NormalMatrixCondition", adjustment.NormalMatrixCondition, ...
    "Converged", adjustment.Converged, ...
    "ContainsFeatureCoordinatesOrDescriptors", false);
end

function value = nestedDiagnostic(diagnostic, name)
value = diagnostic;
while ~isfield(value, name)
    if ~isfield(value, "Base") || ~isstruct(value.Base)
        error("runRpc00bHeightTest:MissingCameraDiagnostic", ...
            "Camera inverse diagnostic does not contain %s.", name);
    end
    value = value.Base;
end
value = value.(name);
end

function figures = displayReport(referenceNative, movingNative, reference, ...
        moving, referenceValid, movingValid, geometry, h, z, policy, ...
        geometryDiagnostic, raw, refined, sgm, alignment, points, costs)
figures = struct;
figures.Inputs = figure(Name="RPC00B Inputs", Color="w");
tiledlayout(figures.Inputs, 2, 3, TileSpacing="compact");
showImage(nexttile, referenceNative, "Native reference");
showImage(nexttile, movingNative, "Native moving");
showImage(nexttile, reference, "Processed reference");
showImage(nexttile, moving, "Processed moving");
showMask(nexttile, referenceValid, "Processed reference valid");
showMask(nexttile, movingValid, "Processed moving valid");

figures.Geometry = figure(Name="RPC00B Geometry and Raw Evidence", Color="w");
tiledlayout(figures.Geometry, 2, 3, TileSpacing="compact");
showTrajectory(nexttile, geometryDiagnostic, h);
showLabelPolicy(nexttile, h, z, policy);
ax = nexttile;
plot(ax, z, costs.', LineWidth=1);
hold(ax, "on");
xline(ax, h(2), "--", "expected", Color=[0.25, 0.25, 0.25]);
hold(ax, "off");
grid(ax, "on"); xlabel(ax, "WGS84 HAE (m)"); ylabel(ax, "ZNCC cost");
title(ax, "Representative unregularized curves");
labels = compose("(%.0f,%.0f)", points(:, 1), points(:, 2));
legend(ax, labels, Location="best");

[planeWarp, ~] = warpedPlanes(geometry, moving, movingValid, h);
roles = ["minimum", "expected", "maximum"];
for k = 1:3
    showImage(nexttile, planeWarp(:, :, k), ...
        sprintf("Moving warped at %s %.3g m", ...
        roles(k), h(k)));
end

figures.Results = figure(Name="RPC00B Normal-Label Results", Color="w");
tiledlayout(figures.Results, 3, 4, TileSpacing="compact");
showHeightMap(nexttile, raw.HeightMetres, raw.Valid, h, ...
    "Raw ZNCC HAE (m)");
showHeightMap(nexttile, refined.RefinedHeightMetres, refined.Valid, h, ...
    "Guarded refined HAE (m)");
showHeightMap(nexttile, sgm.HeightMetres, sgm.Valid, h, ...
    "Frozen SGM HAE (m)");
showMap(nexttile, sgm.HeightMetres - raw.HeightMetres, ...
    sgm.Valid & raw.Valid, "SGM - raw height (m)");
showMap(nexttile, raw.CostMargin, raw.Valid, "Raw cost margin");
showMask(nexttile, raw.Valid, "Raw valid");
showMask(nexttile, raw.Valid & ...
    (raw.LabelIndex == 1 | raw.LabelIndex == numel(z)), ...
    "Raw range-boundary winner");
showMap(nexttile, double(raw.LabelIndex), raw.Valid, ...
    "Raw selected label index");
showMap(nexttile, raw.ObservabilityPixelsPerMetre, raw.Valid, ...
    "Selected dw/dz (px/m)");
showImage(nexttile, alignment.WarpedMovingImage, "SGM-warped moving");
showMap(nexttile, alignment.ReferenceMinusWarpedMoving, alignment.Valid, ...
    "Reference - warped moving");
showLabelFractions(nexttile, z, raw, sgm);

figures.Alignment = uifigure(Name="RPC00B Selected Alignment", ...
    Color="w", Position=[100, 100, 1100, 760]);
layout = uigridlayout(figures.Alignment, [1, 1]);
viewer = viewer2d(layout);
title(viewer, ...
    "Selected alignment: reference magenta, SGM-warped moving green");
imageshow(alignment.ReferenceMovingOverlayRGB, Parent=viewer, ...
    DisplayRangeMode="type-range");
end

function [warped, valid] = warpedPlanes(geometry, moving, movingValid, z)
sz = geometry.ReferenceCamera.ImageSize;
[y, x] = ndgrid(1:sz(1), 1:sz(2));
p = [x(:), y(:)];
nl = numel(z);
warped = nan([sz, nl], "like", moving);
valid = false([sz, nl]);
for k = 1:nl
    [w, projectionValid, inside] = geometry.warp(p, z(k));
    [sample, sampleValid] = HeightSweepArrayKernels.bilinear( ...
        moving, w, ValidMask=movingValid);
    keep = projectionValid & inside & sampleValid;
    plane = sample;
    plane(~keep) = NaN;
    warped(:, :, k) = reshape(plane, sz);
    valid(:, :, k) = reshape(keep, sz);
end
end

function showTrajectory(ax, diagnostic, z)
w = diagnostic.MovingTrajectoryXY;
hold(ax, "on");
for k = 1:size(w, 1)
    plot(ax, squeeze(w(k, 1, :)), squeeze(w(k, 2, :)), "-o", ...
        MarkerSize=2);
end
set(ax, YDir="reverse"); axis(ax, "equal"); grid(ax, "on");
xlabel(ax, "moving x/sample"); ylabel(ax, "moving y/line");
title(ax, sprintf("RPC trajectories: %.3g / %.3g / %.3g m", z));
end

function showLabelPolicy(ax, h, z, policy)
motion = (z - h(1)) .* policy.MedianObservabilityPixelsPerMetre;
plot(ax, z, motion, "o-", MarkerSize=3, LineWidth=1);
hold(ax, "on");
xline(ax, h(2), "--", "expected", Color=[0.25, 0.25, 0.25]);
hold(ax, "off");
grid(ax, "on");
xlabel(ax, "WGS84 HAE (m)");
ylabel(ax, "median displacement from minimum (px)");
title(ax, sprintf("%d labels; target <= %.3g px", ...
    numel(z), policy.TargetProjectedMotionPixels));
end

function showLabelFractions(ax, z, raw, sgm)
n = numel(z);
rawCount = accumarray(double(raw.LabelIndex(raw.Valid)), 1, [n, 1]);
sgmCount = accumarray(double(sgm.LabelIndex(sgm.Valid)), 1, [n, 1]);
rawFraction = rawCount ./ max(sum(rawCount), 1);
sgmFraction = sgmCount ./ max(sum(sgmCount), 1);
plot(ax, z, rawFraction, "-", z, sgmFraction, "-", LineWidth=1.2);
grid(ax, "on");
xlabel(ax, "WGS84 HAE (m)");
ylabel(ax, "selected fraction");
title(ax, "Height-label use");
legend(ax, ["Raw ZNCC", "Frozen SGM"], Location="best");
end

function showImage(ax, image, name)
imagesc(ax, image); axis(ax, "image"); colorbar(ax); title(ax, name);
end

function showMask(ax, mask, name)
imagesc(ax, mask); axis(ax, "image"); colorbar(ax); title(ax, name);
end

function showMap(ax, map, valid, name)
x = map;
x(~valid) = NaN;
imagesc(ax, x); axis(ax, "image"); colorbar(ax); title(ax, name);
end

function showHeightMap(ax, map, valid, h, name)
showMap(ax, map, valid, name);
clim(ax, h([1, 3]));
end

function printReport(report)
fprintf("\nRPC00B normal-label smoke test\n");
fprintf("  reference: %s, native %dx%d, processed %dx%d, band %d\n", ...
    report.Input.ReferenceIdentifier, report.Input.ReferenceNativeSize, ...
    report.Input.ReferenceProcessedSize, report.Input.ReferenceBand);
fprintf("  moving:    %s, native %dx%d, processed %dx%d, band %d\n", ...
    report.Input.MovingIdentifier, report.Input.MovingNativeSize, ...
    report.Input.MovingProcessedSize, report.Input.MovingBand);
fprintf("  WGS84 HAE range [minimum expected maximum] (m): %.6g  %.6g  %.6g\n", ...
    report.Settings.HeightRangeHAEMetres);
fprintf("  generated %d labels at target %.6g px; actual median max %.6g px\n", ...
    report.LabelPolicy.LabelCount, ...
    report.LabelPolicy.TargetProjectedMotionPixels, ...
    report.LabelPolicy.MaximumAdjacentMedianProjectedMotionPixels);
fprintf("  generated HAE labels (m):");
fprintf(" %.6g", report.Settings.HeightLabelsHAEMetres);
fprintf("\n");
fprintf("  downsample factor: %d; workers: %d\n", ...
    report.Input.DownsampleFactor, report.Settings.NumWorkers);
fprintf("  RPC00B SUCCESS [reference moving]: [%d %d]\n", ...
    report.Camera.Reference.Success, report.Camera.Moving.Success);
disp(report.Geometry.PerHeight);
disp(report.LabelDiagnostics.MethodSummary);
disp(report.Timing);
fprintf("  raw throughput: %.6g pixel-labels/s\n", ...
    report.RawZncc.Runtime.PixelLabelsPerSecond);
fprintf("  tracked payloads: cost volume %.3f MiB, SGM %.3f MiB, alignment %.3f MiB\n", ...
    report.Memory.CostVolumeBytes ./ 2^20, ...
    report.Memory.SgmTrackedArrayBytes ./ 2^20, ...
    report.Memory.AlignmentArrayBytes ./ 2^20);
fprintf("  raw boundary winners: %.3f; SGM boundary winners: %.3f\n", ...
    report.LabelDiagnostics.RawBoundaryFraction, ...
    report.LabelDiagnostics.SgmBoundaryFraction);
fprintf("  guarded refinement available on %.3f of raw-valid pixels\n", ...
    report.LabelDiagnostics.RefinementValidFractionOfRaw);
for k = 1:numel(report.Warnings)
    fprintf("  warning [%s]: %s\n", ...
        report.WarningKinds(k), report.Warnings(k));
end
fprintf("  report.Summary is redaction-safe; the full report contains derived raster data.\n\n");
end

function identifier = treIdentifier(source)
if isstruct(source)
    identifier = "decoded-structure";
else
    value = string(source);
    if isfile(value)
        [~, name, extension] = fileparts(value);
        identifier = string(name + extension);
    else
        identifier = "inline-RPC00B-payload";
    end
end
end

function result = columnStatistic(x, operation)
result = nan(size(x, 2), 1);
for k = 1:size(x, 2)
    result(k) = finiteStatistic(x(:, k), operation);
end
end

function result = columnPercentile(x, q)
result = nan(size(x, 2), 1);
for k = 1:size(x, 2)
    result(k) = finitePercentile(x(:, k), q);
end
end

function value = finiteStatistic(x, operation)
x = x(isfinite(x));
if isempty(x)
    value = NaN;
else
    value = operation(x);
end
end

function value = finitePercentile(x, q)
x = sort(x(isfinite(x)));
if isempty(x)
    value = NaN;
    return
end
position = 1 + (numel(x) - 1) .* q ./ 100;
lo = floor(position);
hi = ceil(position);
value = x(lo) + (position - lo) .* (x(hi) - x(lo));
end

function n = bytesPerElement(name)
switch name
    case {"double", "uint64", "int64"}
        n = 8;
    case {"single", "uint32", "int32"}
        n = 4;
    case {"uint16", "int16"}
        n = 2;
    otherwise
        n = 1;
end
end

function mustBeExistingFile(file)
if ~isfile(file)
    error("runRpc00bHeightTest:FileNotFound", ...
        "Input file does not exist: %s", file);
end
end

function mustBeRpcSource(source)
if isstruct(source)
    return
end
if ~(ischar(source) || (isstring(source) && isscalar(source)))
    error("runRpc00bHeightTest:InvalidTreSource", ...
        "TRE source must be a decoded scalar structure, payload, or file path.");
end
end

function mustBeMaskSource(source)
if isempty(source) || islogical(source)
    return
end
if ~(ischar(source) || (isstring(source) && isscalar(source)))
    error("runRpc00bHeightTest:InvalidMaskSource", ...
        "Mask must be empty, a logical array, or an image file path.");
end
if ~isfile(string(source))
    error("runRpc00bHeightTest:MaskNotFound", ...
        "Mask file does not exist: %s", string(source));
end
end

function mustBeStrictlyIncreasing(z)
if any(diff(z) <= 0)
    error("runRpc00bHeightTest:HeightsNotIncreasing", ...
        "HeightRangeHAEMetres [minimum,expected,maximum] must be strictly increasing.");
end
end

function mustBeOptionalNativeRoi(value)
if isempty(value)
    return
end
if numel(value) ~= 4 || any(~isfinite(value)) ...
        || any(value < 1) || any(value ~= fix(value))
    error("runRpc00bHeightTest:InvalidReferenceROI", ...
        "ReferenceROI must be empty or four positive integers " ...
        + "[yStart,yEnd,xStart,xEnd] in native 1x pixels.");
end
end

function mustBeAtMost250(value)
if value > 250
    error("runRpc00bHeightTest:FeatureCapExceeded", ...
        "MaximumFeatures cannot exceed 250 per image.");
end
end
